<?php namespace App\Http\Controllers\KuBo; use App\Http\Controllers\Controller; use App\Models\CommunityPost; use Illuminate\Http\JsonResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\Auth;

class FeedController extends Controller {
    public function load(Request $request): JsonResponse { $user = Auth::user(); $posts = CommunityPost::feed()->paginate(10); $postsData = $posts->map(fn($post) => $this->formatPost($post, $user)); return response()->json(['posts' => $postsData, 'has_more' => $posts->hasMorePages(), 'next_page' => $posts->currentPage() + 1]); }
    private function formatPost(CommunityPost $post, $user): array { $pu = $post->user; $cr = $post->reactions()->where('user_id', $user->empID)->first(); return ['id' => $post->id, 'content' => $post->content, 'content_html' => preg_replace('/#(\w+)/', '<a href="'.route('kubo.hashtag','$1').'" class="text-decoration-none fw-semibold" style="color:#00376b;">#$1</a>', nl2br(e($post->content))), 'is_pinned' => $post->is_pinned, 'is_announcement' => $post->is_announcement, 'created_at' => $post->created_at->diffForHumans(), 'created_at_iso' => $post->created_at->toISOString(), 'user' => ['empID' => $pu->empID ?? '', 'name' => $pu->community_full_name, 'avatar' => $pu->community_avatar, 'department' => $pu->empDetail?->department?->depName ?? '', 'position' => $pu->empDetail?->position?->posDesc ?? ''], 'images' => $post->images->map(fn($img) => ['id' => $img->id, 'url' => asset($img->image_path)]), 'hashtags' => $post->hashtags->pluck('tag'), 'reactions' => ['total' => $post->reactions_count ?? 0, 'summary' => $post->reaction_summary], 'current_reaction' => $cr?->reaction_type, 'comments_count' => $post->comments_count ?? 0, 'reposts_count' => $post->reposts_count ?? 0, 'is_reposted_by_me' => $post->reposts()->where('user_id', $user->empID)->exists(), 'can_delete' => $user->empID === $post->user_id || $user->can('kuboadmin'), 'can_pin' => $user->can('kuboadmin')]; }
}